    @http.route('/real_estate/followup_detail', type='json', auth='user')
    def followup_detail(self, saleperson_id):
        if saleperson_id == 0:
            saleperson_id = False

        invoice_ids = request.env['account.move'].search([
            ('user_id', '=', saleperson_id),
            ('state','=', 'posted'),
            ('move_type', '=', 'out_invoice'),
            ])

        members = list(dict.fromkeys([rec.partner_id for rec in invoice_ids]))

        zero_to_thirty_amount = 0
        thirty_to_ninty_amount = 0
        ninty_to_above_amount = 0

        zero_to_thirty = 0
        thirty_to_ninty = 0
        ninty_to_above = 0

        record = []

        for rec in members:
            for inv in invoice_ids:
                if inv.partner_id.id == rec.id and inv.ageing == 'zero_to_thirty':
                    zero_to_thirty_amount = zero_to_thirty_amount + inv.amount_residual
                    zero_to_thirty = zero_to_thirty + 1
                elif inv.partner_id.id == rec.id and inv.ageing == 'thirty_to_ninty':
                    thirty_to_ninty_amount = thirty_to_ninty_amount + inv.amount_residual
                    thirty_to_ninty = thirty_to_ninty + 1
                elif inv.partner_id.id == rec.id and inv.ageing == 'ninty_to_above':
                    ninty_to_above_amount = ninty_to_above_amount + inv.amount_residual
                    ninty_to_above = ninty_to_above + 1
            
            record.append({
                'id': rec.id,
                'sale_person': saleperson_id,
                'name': rec.name,
                'zero_to_thirty': zero_to_thirty,
                'thirty_to_ninty': thirty_to_ninty,
                'ninty_to_above': ninty_to_above,
                'zero_to_thirty_amount': zero_to_thirty_amount,
                'thirty_to_ninty_amount': thirty_to_ninty_amount,
                'ninty_to_above_amount': ninty_to_above_amount,
                })

            zero_to_thirty_amount = 0
            thirty_to_ninty_amount = 0
            ninty_to_above_amount = 0

            zero_to_thirty = 0
            thirty_to_ninty = 0
            ninty_to_above = 0


        # data = [{
        #     'id': rec.id,
        #     'sale_person': saleperson_id,
        #     'name': rec.partner_id.name,
        #     'zero_to_thirty_amount': rec.residual if rec.ageing == 'zero_to_thirty' else 0,
        #     'thirty_to_ninty_amount': rec.residual if rec.ageing == 'thirty_to_ninty' else 0,
        #     'ninty_to_above_amount': rec.residual if rec.ageing == 'ninty_to_above' else 0,

        # } for rec in invoice_ids]
        
        return record

    @http.route('/real_estate/followup', type='json', auth='user')
    def followup_data(self, **kw):
        data = []
        invoices = request.env['account.move']
        out_invoices = invoices.search([('move_type', '=', 'out_invoice')])
        salepersons = out_invoices.mapped('user_id')
        # check if the user is administrator or saleperson
        current_user = request.env.user
        admin_users = request.env.ref('real_estate.group_plot_sale_manager').mapped('users').ids

        if current_user.id in admin_users:
            data = [{
                'id': rec.id,
                'saleperson': rec.name,
                'zero_to_thirty': self.sm_inv_sc(invoices, rec.id, 'zero_to_thirty'),
                'zero_to_thirty_amount': '%.2f'%self.sm_inv_total(invoices, rec.id, 'zero_to_thirty'),
                'thirty_to_ninty': self.sm_inv_sc(invoices, rec.id, 'thirty_to_ninty'),
                'thirty_to_ninty_amount': '%.2f'%self.sm_inv_total(invoices, rec.id, 'thirty_to_ninty'),
                'ninty_to_above': self.sm_inv_sc(invoices, rec.id, 'ninty_to_above'),
                'ninty_to_above_amount': '%.2f'%self.sm_inv_total(invoices, rec.id, 'ninty_to_above'),
            } for rec in salepersons]

            data.append({
                'id': 0,
                'saleperson': 'Unknown',
                'zero_to_thirty': self.sm_inv_sc(invoices, False, 'zero_to_thirty'),
                'zero_to_thirty_amount': '%.2f'%self.sm_inv_total(invoices, False, 'zero_to_thirty'),
                'thirty_to_ninty': self.sm_inv_sc(invoices, False, 'thirty_to_ninty'),
                'thirty_to_ninty_amount': '%.2f'%self.sm_inv_total(invoices, False, 'thirty_to_ninty'),
                'ninty_to_above': self.sm_inv_sc(invoices, False, 'ninty_to_above'),
                'ninty_to_above_amount': '%.2f'%self.sm_inv_total(invoices, False, 'ninty_to_above'),
            })

        return data

    def sm_inv_sc(self, invoice, rec_id, ageing):
        return invoice.search_count([
            ('move_type', '=', 'out_invoice'),
            ('user_id', '=', rec_id),
            ('state','=', 'posted'),
            ('ageing', '=', ageing)
            ])

    def sm_inv_total(self, invoice, rec_id, ageing):
        return sum(invoice.search([
            ('move_type', '=', 'out_invoice'),
            ('user_id', '=', rec_id),
            ('state','=', 'posted'),
            ('ageing','=', ageing)]).mapped('amount_residual'))